using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Gets the value of a configuration key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? value
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join(", ", AppConfig.Current.Keys);
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings() =>
        JsonSerializer.Serialize(AppConfig.Current, AppConfig.SerializerOptions);

    [McpServerResource(UriTemplate = "config://app/environment", Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironmentInfo() =>
        JsonSerializer.Serialize(new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessorCount = Environment.ProcessorCount
        }, AppConfig.SerializerOptions);
}

using System.Text.Json;

public static class AppConfig
{
    public static readonly JsonSerializerOptions SerializerOptions = new()
    {
        WriteIndented = true
    };

    public static Dictionary<string, string> Current { get; } = new()
    {
        ["AppName"] = "ConfigMcpServer",
        ["Version"] = "1.0.0",
        ["LogLevel"] = "Information",
        ["MaxRetries"] = "3",
        ["TimeoutSeconds"] = "30"
    };
}

